import React, { useState } from 'react';
import api from '../api/axios';
import { useNavigate, Link } from 'react-router-dom';

const Register = () => {
    const [formData, setFormData] = useState({
        email: '', password: '', firstName: '', lastName: '', role: 'CANDIDATE'
    });
    const navigate = useNavigate();

    const handleSubmit = async (e) => {
        e.preventDefault();
        try {
            await api.post('/auth/register', formData);
            alert("Registration successful! Please login.");
            navigate('/login');
        } catch (err) {
            alert(err.response?.data || "Registration failed");
        }
    };

    return (
        <div className="min-h-screen flex items-center justify-center bg-gray-100">
            <form onSubmit={handleSubmit} className="bg-white p-8 rounded-lg shadow-md w-96 space-y-4">
                <h2 className="text-2xl font-bold text-center">Create Account</h2>
                <input type="text" placeholder="First Name" className="w-full p-2 border rounded" 
                    onChange={e => setFormData({...formData, firstName: e.target.value})} required />
                <input type="text" placeholder="Last Name" className="w-full p-2 border rounded" 
                    onChange={e => setFormData({...formData, lastName: e.target.value})} required />
                <input type="email" placeholder="Email" className="w-full p-2 border rounded" 
                    onChange={e => setFormData({...formData, email: e.target.value})} required />
                <input type="password" placeholder="Password" className="w-full p-2 border rounded" 
                    onChange={e => setFormData({...formData, password: e.target.value})} required />
                <select className="w-full p-2 border rounded" value={formData.role}
                    onChange={e => setFormData({...formData, role: e.target.value})}>
                    <option value="CANDIDATE">Candidate</option>
                    <option value="INTERVIEWER">Interviewer</option>
                </select>
                <button type="submit" className="w-full bg-blue-600 text-white p-2 rounded hover:bg-blue-700">Register</button>
                <p className="text-sm text-center">Already have an account? <Link to="/login" className="text-blue-600">Login</Link></p>
            </form>
        </div>
    );
};

export default Register;
